SELECT count(*) FROM title, cast_info, char_name, name, aka_name, movie_companies, company_name WHERE cast_info.movie_id = title.id AND cast_info.person_role_id = char_name.id AND cast_info.person_id = name.id AND aka_name.person_id = name.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id;